// ============================================
// SEED KEYWORDS & COMPETITOR DOMAINS CONFIG
// ============================================
// Edit these for your business. This is the brain of the system.

const config = {
  // Your domain
  yourDomain: 'getplu.com',

  // Competitor domains to crawl
  competitors: [
    { name: 'Wise', domain: 'wise.com', blogPath: '/blog' },
    { name: 'Remitly', domain: 'remitly.com', blogPath: '/blog' },
    { name: 'WorldRemit', domain: 'worldremit.com', blogPath: '/blog' },
    { name: 'Mercury', domain: 'mercury.com', blogPath: '/blog' },
    { name: 'Chime', domain: 'chime.com', blogPath: '/blog' },
    { name: 'Nova Credit', domain: 'novacredit.com', blogPath: '/resources' }
  ],

  // Seed keywords organized by segment
  seedKeywords: {
    // Core product keywords
    core: [
      'build credit as immigrant',
      'credit card for immigrants',
      'neobank for immigrants',
      'no credit history banking',
      'immigrant credit building',
      'credit card no SSN',
      'build credit fast immigrant',
      'banking for non citizens',
      'credit score for newcomers',
      'immigrant friendly bank'
    ],

    // Filipino OFW segment
    ofw: [
      'OFW remittance fees',
      'OFW banking abroad',
      'Filipino credit card abroad',
      'OFW savings account',
      'Philippine remittance cheapest',
      'OFW financial planning',
      'balikbayan banking',
      'OFW credit building',
      'Filipino worker banking UK',
      'Filipino worker banking Dubai'
    ],

    // Nigerian diaspora segment
    nigerian: [
      'Nigerian diaspora banking',
      'Japa banking guide',
      'Nigerian immigrant credit UK',
      'naira to dollar best rate',
      'Nigerian abroad bank account',
      'japa financial planning',
      'Nigerian credit building US',
      'send money to Nigeria cheap',
      'Nigerian diaspora fintech',
      'banking for Nigerians in Canada'
    ],

    // US immigrant segment
    us_immigrant: [
      'H1B visa credit card',
      'F1 student credit card',
      'ITIN credit card',
      'build credit with ITIN',
      'immigrant credit score US',
      'new to US banking',
      'credit builder for visa holders',
      'secured credit card immigrants',
      'credit union for immigrants',
      'green card holder banking'
    ],

    // Niche use-case segments (matching your landing pages)
    niche: [
      'gamer banking international',
      'crypto worker banking',
      'content creator banking abroad',
      'healthcare worker abroad banking',
      'remote worker international banking',
      'digital nomad credit card',
      'freelancer credit building',
      'zero forex fee card',
      'international student banking',
      'expat credit card'
    ]
  }
};

// Flatten all keywords for processing
const allKeywords = [];
for (const [segment, keywords] of Object.entries(config.seedKeywords)) {
  keywords.forEach(kw => {
    allKeywords.push({ keyword: kw, segment, priority: segment === 'core' ? 1 : 2 });
  });
}

return [
  {
    json: {
      config,
      allKeywords,
      totalKeywords: allKeywords.length,
      competitors: config.competitors,
      runDate: new Date().toISOString(),
      runId: `run_${Date.now()}`
    }
  }
];

// Process search results into structured keyword data
const items = $input.all();
const results = [];

for (const item of items) {
  const keyword = item.json.keyword || 'unknown';
  const segment = item.json.segment || 'unknown';
  const searchData = item.json.data?.web || item.json.data || [];

  const topResults = (Array.isArray(searchData) ? searchData : []).slice(0, 10).map((r, i) => ({
    position: i + 1,
    url: r.url || '',
    title: r.title || '',
    description: r.description || '',
    domain: r.url ? new URL(r.url).hostname : ''
  }));

  // Check if our domain appears
  const ourPosition = topResults.findIndex(r => 
    r.domain.includes('getplu.com') || r.domain.includes('plu.com')
  );

  // Identify which competitors appear
  const competitorPositions = {};
  const competitors = ['wise.com', 'remitly.com', 'worldremit.com', 'mercury.com', 'chime.com', 'novacredit.com'];

  topResults.forEach(r => {
    competitors.forEach(comp => {
      if (r.domain.includes(comp)) {
        competitorPositions[comp] = r.position;
      }
    });
  });

  results.push({
    keyword,
    segment,
    resultCount: topResults.length,
    ourPosition: ourPosition >= 0 ? ourPosition + 1 : null,
    ourRanking: ourPosition >= 0 ? 'RANKING' : 'NOT_RANKING',
    competitorPositions,
    topResults,
    opportunity: ourPosition < 0 ? 'HIGH' : (ourPosition > 4 ? 'MEDIUM' : 'LOW'),
    contentGap: ourPosition < 0,
    scrapedAt: new Date().toISOString()
  });
}

return results.map(r => ({ json: r }));

// Extract competitor content intelligence
const items = $input.all();
const competitorInsights = [];

for (const item of items) {
  const competitor = item.json.name || 'Unknown';
  const pages = item.json.data || [];

  const processedPages = (Array.isArray(pages) ? pages : []).map(page => {
    const markdown = page.markdown || '';
    const metadata = page.metadata || {};

    // Extract headings from markdown
    const h1s = (markdown.match(/^# .+$/gm) || []).map(h => h.replace('# ', ''));
    const h2s = (markdown.match(/^## .+$/gm) || []).map(h => h.replace('## ', ''));

    // Estimate word count
    const wordCount = markdown.split(/\s+/).length;

    return {
      url: metadata.sourceURL || page.url || '',
      title: metadata.title || h1s[0] || 'Untitled',
      description: metadata.description || '',
      headings: { h1s, h2s },
      wordCount,
      hasImages: markdown.includes('!['),
      hasLinks: markdown.includes('['),
      estimatedReadTime: Math.ceil(wordCount / 200)
    };
  });

  competitorInsights.push({
    competitor,
    domain: item.json.domain,
    pagesAnalyzed: processedPages.length,
    pages: processedPages,
    avgWordCount: processedPages.length > 0 
      ? Math.round(processedPages.reduce((a, p) => a + p.wordCount, 0) / processedPages.length)
      : 0,
    topics: processedPages.map(p => p.title),
    analyzedAt: new Date().toISOString()
  });
}

return competitorInsights.map(ci => ({ json: ci }));

// Merge keyword results and competitor insights
const keywordData = $('Process Search Results').all().map(i => i.json);
const competitorData = $('Process Competitor Data').all().map(i => i.json);

// Build the unified report
const report = {
  runId: $('Load Config & Keywords').first().json.runId,
  runDate: $('Load Config & Keywords').first().json.runDate,
  summary: {
    totalKeywordsAnalyzed: keywordData.length,
    keywordsRanking: keywordData.filter(k => k.ourRanking === 'RANKING').length,
    keywordsNotRanking: keywordData.filter(k => k.ourRanking === 'NOT_RANKING').length,
    highOpportunity: keywordData.filter(k => k.opportunity === 'HIGH').length,
    competitorsAnalyzed: competitorData.length
  },

  // Keywords grouped by segment
  keywordsBySegment: {},

  // Content gaps (keywords we don't rank for)
  contentGaps: keywordData.filter(k => k.contentGap).map(k => ({
    keyword: k.keyword,
    segment: k.segment,
    competitorsRanking: Object.keys(k.competitorPositions),
    topResult: k.topResults[0]
  })),

  // Competitor intelligence
  competitorIntel: competitorData.map(c => ({
    name: c.competitor,
    pagesFound: c.pagesAnalyzed,
    avgWordCount: c.avgWordCount,
    recentTopics: c.topics.slice(0, 10)
  })),

  // All keyword data for Claude analysis
  rawKeywordData: keywordData,
  rawCompetitorData: competitorData
};

// Group keywords by segment
keywordData.forEach(k => {
  if (!report.keywordsBySegment[k.segment]) {
    report.keywordsBySegment[k.segment] = [];
  }
  report.keywordsBySegment[k.segment].push({
    keyword: k.keyword,
    ourPosition: k.ourPosition,
    opportunity: k.opportunity,
    topCompetitor: Object.entries(k.competitorPositions)[0] || null
  });
});

return [{ json: report }];

