// Parse Claude's response and structure the final output
const claudeResponse = $input.first().json;
const reportData = $('Merge & Build Report').first().json;

let analysis;
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  // Strip markdown fences if present
  const clean = content.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(clean);
} catch (e) {
  analysis = {
    weeklyBrief: {
      headline: 'Analysis parsing failed - review raw data',
      topOpportunities: [],
      contentCalendar: [],
      competitorMoves: [],
      quickWins: ['Review raw keyword data manually'],
      error: e.message
    }
  };
}

const finalReport = {
  ...reportData,
  analysis: analysis.weeklyBrief || analysis,
  generatedAt: new Date().toISOString()
};

return [{ json: finalReport }];

